var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈……哈……"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이전 침식 사태의 대응으로 미약하게나마 별빛의 본질을 깨달으신 모양이군요.","JPN":"この前の侵食事態に対応しているうちに、少しですが星の光の本質に気が付かれているようですね。","ENG":"It seems the last Corruption disaster helped you grasp the essence of starlight, even if only slightly.","TWN":"看起來你在應對之前的侵蝕事件時，稍微領悟到了星光的本質。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 움직임이 부자연스럽습니다. 혹, 다른 누군가를 모방해내는 것 같군요.","JPN":"ですが、まだ動きが不自然です。まるで誰かのそれを真似ているかのように。","ENG":"But your movements are unnatural. It's as if you're imitating someone else.","TWN":"但你的動作顯得不自然。或許是在模仿其他人吧。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금 그걸 말이라고 하십니까?","JPN":"何ですか、それは！","ENG":"Is that really what you're going to say right now?","TWN":"你現在是在說什麼？"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"읏!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃！?"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이게 무슨 짓입니까, 부인!","JPN":"どういうつもりですか、夫人！","ENG":"What are you doing, madam?!","TWN":"夫人，你這是在做什麼！"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"마지막 한 사람이 남을 때까지 계속하여 싸운다 말하지 않았습니까?","JPN":"最後の一人になるまで戦い続ける、と言ったはずですよ？","ENG":"Didn't I say the battle continues until only one person remains?","TWN":"不是說要戰鬥到最後一個人嗎？"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"명색이 가문의 후계자가 제 가문 기사들의 추태를 보고 있을 수는 없는 법이지요.","JPN":"一族の後継者たる者、家門の騎士たちの醜態を見ているだけというわけにはいきませんから。","ENG":"As the heir of a noble house, I can't just sit back and watch my knights disgrace themselves.","TWN":"身為家族的繼承人，我不能坐視家族騎士們出醜。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"가호가 불안정해진 뒤로 몸이 뒤쳐질지 언정 판단이 뒤쳐지는 경우는 없었다.","JPN":"加護が不安定になってからというもの、体が遅れることはあっても判断が遅れることはなかった。","ENG":"Even after my blessing destabilized, my body lagged behind, not my judgment.","TWN":"即使在守護變得不穩定之後，身體可能會慢一拍，但判斷從未落後。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그런데 검의 궤적을 눈으로 쫓는 게 고작이라고?","JPN":"なのに、剣の軌跡を目で追うだけで精一杯だ。","ENG":"But all I can do is track her sword with my eyes?","TWN":"但是只能用眼睛追蹤劍的軌跡嗎？"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"청출어람이 되어버렸으나 알렌에게 검술을 가르친 건 저입니다.","JPN":"出藍の誉れとなってしまいましたが、アレンに剣術を教えたのは私なのです。","ENG":"He may have surpassed me, but I was the one who taught Allen how to wield a sword.","TWN":"青出於藍，但教艾倫劍術的是我。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그런 맥아리 없는 검술에 당하면 체면이 안 서지요.","JPN":"そのような気の弱い剣術にやられては、示しがつきません。","ENG":"Losing to such a limp excuse for swordsmanship would be embarrassing.","TWN":"被那種無力的劍術擊敗的話，顏面何存呢。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"매, 맥아리?","JPN":"気の弱い？","ENG":"L-limp?!","TWN":"什，什麼？"},"stage":{"bg":"CORRIDOR_10","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"내 검의 궤도를… 전부 앞질렀어?","JPN":"私の剣の軌道を……全部見抜いている？","ENG":"She read... every move of my blade?!","TWN":"我的劍軌……全部被你提前知道了？"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무구를 통해 빚어낸 별빛이란 또한 기사의 내면을 비추는 심상과도 같습니다.","JPN":"武具を通じて作り出した星の光とは、騎士の内面が映し出されたもの。","ENG":"The starlight channeled through an Armament reflects the inner image of its wielder.","TWN":"通過武器打造出的星光，也如同騎士內心的意象一般。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"검술이 동작의 반복을 넘어 몸과 마음의 일치를 추구하는 것이 시작점이듯.","JPN":"剣術が、動作の繰り返しに留まらず、体と心の一体化を追求することから始めるように。","ENG":"Just as swordsmanship begins with unifying mind and body beyond mere repetition of movements.","TWN":"劍術的起點在於追求動作的重複超越身體與心靈的統一。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"적이 다루는 별빛을 읽어낼 수 있다면 그 움직임을 읽어내는 것은 쉬운 일이지요.","JPN":"敵が扱う星の光を読むことができれば、その動きを見抜くのはたやすいことです。","ENG":"Once you can read the starlight an opponent wields, anticipating their moves becomes simple.","TWN":"如果能解讀敵人操控的星光，那麼讀懂他們的動作就容易了。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자, 경께서도 따라해보세요.","JPN":"さあ、卿もどうぞご一緒に。","ENG":"Now then, why don't you give it a try?","TWN":"來，你也試著跟著做吧。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그런 게 가능했다면 이런 고생은 안 합니다!","JPN":"そのようなことができたなら、ここまで苦労はしません！","ENG":"If it were that easy, I wouldn't be struggling like this!","TWN":"如果那樣能行的話，我就不用這麼辛苦了！"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음. 집중할 동기가 부족하다면 이렇게 하지요.","JPN":"そうですか。集中する動機が足りないのでしたら、こういたしましょう。","ENG":"Hmm. If you're lacking the motivation to focus, then allow me to fix that.","TWN":"嗯。如果缺乏集中注意力的動力，那就這樣做吧。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"만약 경께서 제 방어를 뚫어 내신다면, 하나의 <color=#ffd34c>질문</color>에 한해 어떤 것이든 답변하겠습니다.","JPN":"もし卿が私の防御を突破することができたなら、どんな<color=#ffd34c>質問</color>でも一つに限りお答えします。","ENG":"If you can break through my defense, I'll answer any one <color=#ffd34c>question</color> you ask.","TWN":"如果你能突破我的防禦，我將回答一個<color=#ffd34c>問題</color>，無論是什麼問題。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 제 말문이 막힐 정도로 날카로운 질문 말이죠.","JPN":"ええ。それはもう、私が言葉を失うほど鋭い質問でも。","ENG":"Yes. Even one so sharp it leaves me speechless.","TWN":"沒錯，令我難以啟齒的尖銳問題也可以。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"후회하실 겁니다.","JPN":"後悔しますよ。","ENG":"You'll regret that.","TWN":"你會後悔的。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 무서워라.","JPN":"あら、怖い。","ENG":"Oh my. How scary.","TWN":"哎呀，真可怕呀。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"호승심 넘치게 말했으나 상대의 공격은 눈으로 쫓는 게 고작이다.","JPN":"自信満々に言いはしたが、相手の攻撃を目で追うのが精一杯。","ENG":"She boasted with confidence, but all she could manage was to follow her opponent's attacks with her eyes.","TWN":"雖然說得很有鬥志，但只能用眼睛追蹤對方的攻擊。"},"stage":{"bg":"CORRIDOR_10","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};